import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val adj = Array<MutableList<Array<Long>>>(n.toInt()) { mutableListOf() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val s = edge[2]
        val e = edge[3]
        adj[u].add(arrayOf(v.toLong(), s, e))
    }

    val dist = LongArray(n.toInt()) { Long.MAX_VALUE }
    dist[0] = 0L

    val pq = PriorityQueue<Pair<Long, Int>> { a, b -> a.first.compareTo(b.first) }
    pq.add(Pair(0L, 0))

    while (pq.isNotEmpty()) {
        val (time, u) = pq.poll()
        if (u == n.toInt() - 1) return time
        if (time > dist[u]) continue

        // Stay at current node
        val nextTimeStay = time + 1
        if (nextTimeStay < dist[u]) {
            dist[u] = nextTimeStay
            pq.add(Pair(nextTimeStay, u))
        }

        // Check all edges from u
        for (edge in adj[u]) {
            val v = edge[0].toInt()
            val s = edge[1]
            val e = edge[2]
            if (time >= s && time <= e) {
                val nextTime = time + 1
                if (nextTime < dist[v]) {
                    dist[v] = nextTime
                    pq.add(Pair(nextTime, v))
                }
            }
        }
    }

    return -1L
}
